INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('60eb4d6a2b2f7536', 'CT', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in Connecticut?', '["Are Connecticut primaries open or closed?","Do I have to register with a party to vote in the CT primary?","Can unaffiliated voters participate in the Connecticut primary?"]', 'Connecticut utilizes a strictly closed primary system. Voters must be formally registered as a member of a political party (Democratic or Republican) to participate in that party''s primary election. Unaffiliated voters cannot vote in partisan primaries.', 'https://portal.ct.gov/SOTS/Election-Services/Voter-Information/Voter-Registration-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('f00ca3b56d4ed01b', 'CT', '["federal","state","county"]', 'voter_interaction', 'What is the party change deadline for Connecticut primary elections?', '["When do I have to switch parties to vote in the CT primary?","Connecticut party registration deadline","May party switch deadline Connecticut"]', 'Under Connecticut law, voters who are registered with a minor party or wish to switch between major parties must do so exactly three months before the primary. For the August 11, 2026 primary, the deadline to switch party affiliation is May 11, 2026. (Unaffiliated voters can enroll in a party up until the day before the primary).', 'https://portal.ct.gov/SOTS/Election-Services/Voter-Information/Voter-Registration-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('0fe8e34839c0729a', 'CT', '["federal","state"]', 'ballot_access', 'What is the convention delegate threshold to qualify for the Connecticut primary ballot?', '["Connecticut 15 percent rule primary","How do candidates get on the ballot in CT?","Party convention rules Connecticut primary"]', 'Connecticut has a highly distinctive ballot access process. Major party candidates must first go through a party convention. A candidate automatically qualifies for the primary ballot if they receive at least 15% of the delegate votes at the convention. If a candidate fails to reach the 15% threshold, they must collect petition signatures from 2% of enrolled party members in their district to force a primary.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Major party candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('16e330d1e2f747c9', 'CT', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for Connecticut in 2026?', '["When do candidates file for office in Connecticut?","Connecticut filing deadline 2026","June filing deadline CT"]', 'For major party candidates attempting to petition onto the primary ballot (if they did not receive the convention endorsement or the 15% threshold), the primary petition filing deadline is June 9, 2026.', 'https://portal.ct.gov/SOTS/Election-Services/Calendars/Election-Calendars', 'Connecticut Secretary of the State', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('95665214c0103d48', 'CT', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in Connecticut?', '["Do write-in votes count in CT?","How to register as a write-in candidate in Connecticut","Write-in filing deadline Connecticut"]', 'Yes. Write-in candidates are permitted in the general election, but write-in votes are only tabulated if the candidate has officially registered their candidacy. The candidate must file a registration of write-in candidacy with the Secretary of the State no later than 14 days prior to the election.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('dba1e6ed4e1e610f', 'CT', '["federal","state","county"]', 'ballot_access', 'Does Connecticut have a sore loser law?', '["Can I run as an independent if I lose the CT primary?","Connecticut sore loser statute","General election ballot access after primary defeat CT"]', 'Yes. Connecticut enforces a sore loser law. A candidate who runs and loses in a major party''s primary election cannot subsequently appear on the general election ballot as an independent or minor party candidate for the same office.', 'https://ballotpedia.org/Sore_loser_laws_by_state', 'Ballotpedia - Sore Loser Laws', '2026-05-17', 'static', 'secondary_source', 'Major party candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('086223186c6109ca', 'CT', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Connecticut?', '["Connecticut joint ticket rules","How are Lt Gov candidates selected in CT?","Does the Governor pick a running mate in Connecticut?"]', 'In Connecticut, candidates for Governor and Lieutenant Governor run in separate primary elections but run on a joint, single ticket in the general election. Voters cast a single vote for the combined ticket in November.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('574fef4e0602d274', 'CT', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Connecticut for 2026?', '["Connecticut primary date 2026","When is Election Day 2026 in Connecticut?","August primary Connecticut"]', 'The Connecticut primary election is scheduled for Tuesday, August 11, 2026. The general election will be held on Tuesday, November 3, 2026. Plurality wins the primary, so there are no primary runoffs.', 'https://portal.ct.gov/SOTS/Election-Services/Calendars/Election-Calendars', 'Connecticut Secretary of the State - Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('53b15c730342b622', 'CT', '["state"]', 'election_dates', 'Is Governor Ned Lamont running for re-election in 2026?', '["Connecticut Governor election 2026","Who is defending the CT Governor seat?","Is Ned Lamont term limited?"]', 'Yes. Governor Ned Lamont (D) is eligible to defend his seat in the 2026 election, seeking a third term. Connecticut is one of a minority of states that does NOT impose term limits on its Governor.', 'https://ballotpedia.org/Governor_of_Connecticut', 'Ballotpedia - Governor of Connecticut', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('55a1256285521284', 'CT', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Connecticut in 2026?', '["Is Chris Murphy up for re-election in 2026?","When is Richard Blumenthal''s next election?","Connecticut US Senate cycle 2026"]', 'Neither U.S. Senate seat in Connecticut is on the ballot in 2026. Senator Chris Murphy (Class 1) was re-elected in 2024 and is next up in 2030. Senator Richard Blumenthal (Class 3) was re-elected in 2022 and is next up in 2028.', 'https://www.senate.gov/senators/Class_I.htm', 'U.S. Senate - Class I Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('919f039f75e91c69', 'CT', '["federal"]', 'election_dates', 'How many U.S. House districts are in Connecticut for the 2026 election?', '["Connecticut congressional apportionment","Are all CT congressional seats up in 2026?","Number of US Representatives from Connecticut"]', 'Connecticut is apportioned 5 U.S. House districts. All five seats are on the 2026 ballot, as U.S. Representatives serve two-year terms.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('c15fb2a420f39201', 'CT', '["state"]', 'election_dates', 'Which Connecticut State Legislature seats are up for election in 2026?', '["Are all Connecticut House seats up in 2026?","Connecticut Senate election cycle 2026","Which legislative districts are on the ballot in CT?"]', 'In Connecticut, all members of the General Assembly serve two-year terms. Therefore, all 151 seats in the Connecticut House of Representatives and all 36 seats in the Connecticut State Senate are on the 2026 ballot.', 'https://www.cga.ct.gov/', 'Connecticut General Assembly', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('1fcb0a910c4a5268', 'CT', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Connecticut in 2026?', '["Is the Attorney General up in 2026?","CT statewide election list 2026","When is the Secretary of State election in CT?"]', 'Connecticut elects all of its statewide executive officers concurrently on a four-year midterm cycle. In 2026, the offices of Governor, Lieutenant Governor, Attorney General, Secretary of the State, State Treasurer, and State Comptroller are all on the ballot.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('fddd74ee63f08322', 'CT', '["judicial"]', 'election_dates', 'How are Connecticut Supreme Court justices selected and are they on the ballot?', '["Connecticut judicial elections 2026","Are CT judges elected or appointed?","Supreme Court elections Connecticut"]', 'Connecticut does NOT hold judicial elections. Supreme Court justices are nominated by the Governor from a list provided by a judicial selection commission, and must be approved by the General Assembly for an eight-year term. They never appear on a public ballot.', 'https://www.jud.ct.gov/', 'State of Connecticut Judicial Branch', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('2d3e860b5f8cede1', 'CT', '["state"]', 'election_dates', 'What is the schedule for the Connecticut General Assembly sessions?', '["When does the CT legislature meet?","Connecticut short session length","Is the Connecticut legislature full time?"]', 'The Connecticut General Assembly is a part-time legislature. In odd-numbered years, it holds a ''long session'' (January to June). In even-numbered election years (like 2026), it holds a ''short session'' running from early February to early May. For 2026, the session convenes on February 4 and adjourns on May 6.', 'https://www.cga.ct.gov/', 'Connecticut General Assembly', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('59357dfb42a9df70', 'CT', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Connecticut?', '["Age and residency for Connecticut Governor","Connecticut Constitution Governor qualifications","Who is eligible to be Governor of CT?"]', 'Under Article IV of the Connecticut Constitution, a candidate for Governor must be at least 30 years old and must have been a registered voter (elector) in the state of Connecticut for at least one year immediately preceding the election.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('299df9541e143dd8', 'CT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Connecticut State Legislature?', '["Qualifications for CT State Representative","Age requirement Connecticut State Senate","Do I have to live in my district to run in CT?"]', 'A candidate for the State Senate or House of Representatives in Connecticut must be at least 18 years old and a registered voter in the state. Candidates must reside in the district they are elected to represent by the time they take office.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('5e3aaea2dc33719d', 'CT', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House candidates in Connecticut?', '["US House residency requirements Connecticut","Age to run for Congress in Connecticut","Federal constitutional requirements for CT candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('930cadab8bb97e56', 'CT', '["state"]', 'candidate_eligibility', 'What are the term limits for the Connecticut Governor?', '["How many terms can a Connecticut Governor serve?","Ned Lamont term limits CT","Connecticut executive term limit law"]', 'Connecticut does not impose term limits on its Governor or any of its statewide executive officers. Governor Ned Lamont is fully eligible to seek a third consecutive term in 2026.', 'https://ballotpedia.org/Governor_of_Connecticut', 'Ballotpedia - Governor of Connecticut', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('36bc45bc3aac5ce0', 'CT', '["state"]', 'candidate_eligibility', 'Does Connecticut have legislative term limits?', '["How many terms can a Connecticut state senator serve?","Are there term limits for the Connecticut House?","Connecticut legislature term limit status"]', 'No. Connecticut does not impose term limits on members of the State Senate or the House of Representatives. State legislators may serve an unlimited number of two-year terms as long as they continue to win re-election.', 'https://www.cga.ct.gov/', 'Connecticut General Assembly', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('8886ba6c63702483', 'CT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Connecticut?', '["Connecticut Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in CT?","Qualifications for Lieutenant Governor of Connecticut"]', 'Under Article IV of the Connecticut Constitution, the qualifications for Lieutenant Governor are identical to those for Governor. A candidate must be at least 30 years old and a registered voter in Connecticut for at least one year immediately preceding the election.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('b37b2ad67111a914', 'CT', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Connecticut?', '["Connecticut county executive qualifications","Can I run for county council in CT?","County residency for CT officials"]', 'In a major distinctive feature, Connecticut completely abolished county government in 1960. There are no county elections, county executives, or county councils. All local government is conducted at the town and city level across the state''s 169 municipalities.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('765746bdf2d926c0', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a strict photo ID required to vote in person in Connecticut?', '["Connecticut voter ID requirements","Do I need my driver''s license to vote in CT?","Acceptable ID for Connecticut voting"]', 'No. Connecticut is not a strict photo ID state. Voters are asked to present ID, but a photo is not required. Acceptable ID includes any document bearing the voter''s pre-printed name and address, signature, or photograph (such as a utility bill, paycheck, or Social Security card). If a voter has no ID, they can sign an affidavit attesting to their identity under penalty of false statement.', 'https://portal.ct.gov/SOTS/Election-Services/FAQ/FAQ---Voter-Identification', 'Connecticut Secretary of the State - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('50a5a382731a2241', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Connecticut a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in Connecticut?","Connecticut vote-by-mail system","Do I need an excuse to vote absentee in CT?"]', 'Connecticut is not a universal mail ballot state, but as of May 2026, it is officially a NO-EXCUSE absentee voting state. Following a constitutional amendment ratified by voters in 2024, the legislature passed HB 5001, effectively removing all specific excuse requirements to cast an absentee mail ballot. Any registered voter may now request one.', 'https://www.senatedems.ct.gov/sen-maher-votes-for-more-democracy-in-connecticut-with-new-absentee-voter-bill', 'Connecticut General Assembly (HB 5001)', '2026-05-17', 'volatile', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('88ecdd97d45cdded', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Connecticut offer early in-person voting?', '["Can I vote early in person in CT?","Connecticut early voting dates 2026","When does early voting start in Connecticut?"]', 'Yes. Connecticut instituted in-person Early Voting beginning in 2024. For the 2026 primary elections, early voting is held for 7 days (August 3 to August 9). For the general election, early voting is held for 14 days (typically October 19 to November 1).', 'https://portal.ct.gov/SOTS/Election-Services/Early-Voting/Early-Voting', 'Connecticut Secretary of the State - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('1f0dd5ff2e513650', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Connecticut offer same-day registration?', '["Last day to register to vote in CT","Connecticut same day voter registration","Voter registration deadline 2026 Connecticut"]', 'The standard advance deadline to register to vote in Connecticut is 7 days before Election Day (online, by mail, or in person). However, Connecticut DOES offer Same-Day Registration (SDR). Eligible voters can register and vote on the same day during the entire Early Voting period and on Election Day at designated SDR locations in their town.', 'https://portal.ct.gov/SOTS/Election-Services/Voter-Information/Voter-Registration-Information', 'Connecticut Secretary of the State - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('6eebd1882f90c6cd', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Connecticut?', '["How close can I campaign to a polling place in CT?","Connecticut 75 feet electioneering rule","CT buffer zone around voting centers"]', 'Under Connecticut law, electioneering is strictly prohibited within 75 feet of any outside entrance to the polling place. Campaigning, distributing literature, and placing signs are not allowed within this zone on Election Day or during Early Voting.', 'https://portal.ct.gov/SOTS/Election-Services/FAQ/FAQ---Voter-Rights', 'Connecticut Secretary of the State - Election Day Rules', '2026-05-17', 'static', 'official_source_direct', 'Campaign workers and Voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('6ea096ec36a81279', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Connecticut?', '["Can felons vote in Connecticut state?","Felony voting rights restoration CT","Voting on parole in Connecticut"]', 'In Connecticut, individuals with felony convictions lose their voting rights only while they are incarcerated. Following a 2021 law signed by Gov. Lamont, voting rights are automatically restored immediately upon release from prison. Individuals on probation or parole are fully eligible to vote.', 'https://portal.ct.gov/SOTS/Election-Services/Voter-Information/Voter-Registration-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('6e18b46210337f2b', 'CT', '["county"]', 'voter_interaction', 'How many counties are in Connecticut, and how does this affect election administration?', '["Connecticut county election administration","How many county clerks in CT?","Local election control Connecticut towns"]', 'While Connecticut has 8 geographic counties, it has NO county government. Election administration is handled entirely at the municipal level by the Registrars of Voters and Town Clerks across the state''s 169 towns and cities. Statewide campaigns must coordinate logistics across 169 separate local jurisdictions.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('bd0052a5ab9c8378', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Connecticut voter file?', '["Connecticut voter database access cost","How to get the voter list in CT","What data is included in the Connecticut voter file?"]', 'Campaigns and political committees can request the statewide voter registration list from the Secretary of the State''s office. The file includes voter names, addresses, party affiliation, and voting history. It requires an application and payment, and its use is legally restricted to political and election purposes.', 'https://portal.ct.gov/SOTS/Election-Services/Voter-Information/Voter-Registration-Data', 'Connecticut Secretary of the State - Voter Data', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('81720d6c99830025', 'CT', '["state"]', 'finance_ethics', 'Does Connecticut provide public financing for state campaigns?', '["Public matching funds for Connecticut Governor","Citizens Election Program CT status","Government campaign grants Connecticut Legislature"]', 'Yes. Connecticut runs the Citizens'' Election Program (CEP), a highly comprehensive public financing system. Candidates for statewide offices and the General Assembly who gather a required threshold of small-dollar qualifying contributions agree to strict spending limits in exchange for full public grant funding for their primary and general campaigns.', 'https://seec.ct.gov/Portal/CEP', 'Connecticut State Elections Enforcement Commission - CEP', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('5c87ef06140e9e2b', 'CT', '["state"]', 'finance_ethics', 'What are the individual campaign contribution limits for non-participating candidates in Connecticut?', '["Are there contribution limits in Connecticut?","CT individual donation caps 2026 election","Maximum donation to state legislature Connecticut"]', 'For candidates who do NOT participate in the public financing CEP, contribution limits are very low. For the 2026 cycle, individuals may contribute up to $3,500 to a gubernatorial candidate, $1,000 to a State Senate candidate, and $250 to a State Representative candidate. These limits apply separately to the primary and general elections.', 'https://www.cga.ct.gov/2008/rpt/2008-R-0316.htm', 'Connecticut General Assembly - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('ecb79401163f9984', 'CT', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Connecticut campaigns?', '["Corporate contribution ban Connecticut state","Can a business donate to my campaign in CT?","Corporate campaign finance rules Connecticut"]', 'No. In a major distinctive feature of state law, Connecticut strictly PROHIBITS direct contributions from corporations and labor unions to state candidate committees, exploratory committees, and political party committees. They may only establish separate PACs funded by voluntary employee donations.', 'https://publicintegrity.org/politics/state-bans-on-soft-money/', 'Connecticut Campaign Finance Law', '2026-05-17', 'static', 'secondary_source', 'Candidates and Businesses', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('13e58e7752e7c3df', 'CT', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Connecticut?', '["Where do I file campaign finance reports in CT?","What is the Connecticut SEEC?","Does the CT Secretary of State handle campaign finance?"]', 'Campaign finance and disclosure laws in Connecticut are administered by the State Elections Enforcement Commission (SEEC). The SEEC manages the eCRIS online reporting system, audits campaigns, manages the Citizens'' Election Program (CEP), and investigates election law violations.', 'https://seec.ct.gov/', 'Connecticut State Elections Enforcement Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('f1b7a79094ad4391', 'CT', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Connecticut candidates?', '["CT SEEC filing dates 2026","When are campaign finance reports due in CT?","Connecticut pre-primary and pre-general report deadlines"]', 'Candidates use the eCRIS system to file standard quarterly reports (January, April, July, October). During an election year, candidates on the ballot must also file critical pre-election reports due on the 7th day preceding a primary and the 7th day preceding the general election.', 'https://seec.ct.gov/Portal/eCRIS/eCRISHome', 'Connecticut SEEC - eCRIS', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('83b577cafc20b0f9', 'CT', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Connecticut?', '["CT personal use prohibition campaign finance","Can I use campaign money for personal items in CT?","Prohibited expenditures Connecticut SEEC"]', 'Yes. Connecticut law strictly prohibits the use of campaign funds for the personal use of the candidate or any other individual. Expenditures must be directly related to the campaign. Candidates participating in the public financing CEP program face even stricter scrutiny and exhaustive audits on all expenditures.', 'https://seec.ct.gov/Portal/data/CEP/news/2026CEPOverview.pdf', 'Connecticut SEEC - 2026 CEP Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('7f67951293213c94', 'CT', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Connecticut legislators?', '["Can Connecticut legislators raise money during session?","Lobbyist contribution ban CT legislature","Legislative session contribution rules Connecticut"]', 'Yes. Connecticut enforces a strict ''session freeze'' on lobbyist contributions. During regular legislative sessions (and certain special sessions), lobbyist contributions to candidates for the General Assembly and statewide office are completely banned. Recent 2025 legislation (HB 6320) also expanded this freeze to prohibit lobbyist donations to state legislators who are running for municipal offices during the session.', 'https://www.cga.ct.gov/2025/ba/pdf/2025HB-06320-R000682-BA.pdf', 'Connecticut General Assembly (HB 6320)', '2026-05-17', 'static', 'statute_citation', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('60c7fa66d076e8f1', 'CT', '["state","county","municipal"]', 'finance_ethics', 'What are Connecticut''s rapid disclosure requirements for late contributions?', '["Connecticut 48-hour large contribution report","Late contribution reporting Connecticut SEEC","When do I file a rapid report in CT?"]', 'Connecticut requires rapid disclosure for late contributions. Candidates and committees receiving a contribution of $1,000 or more during the final days before an election (between the cut-off for the last pre-election report and Election Day) must report the contribution to the SEEC within 48 hours of receipt.', 'https://seec.ct.gov/Portal/eCRIS/eCRISHome', 'Connecticut SEEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('7c2cfd851883ed58', 'CT', '["state"]', 'finance_ethics', 'What are the qualifying thresholds for Connecticut''s Citizens'' Election Program (CEP)?', '["How do I qualify for public financing in Connecticut?","CEP qualifying contributions CT","Connecticut CEP threshold amounts"]', 'To qualify for the Citizens'' Election Program (CEP), candidates must raise an aggregate threshold of small-dollar contributions (between $5 and $320) from a minimum number of unique in-district or in-state contributors. For 2026, a gubernatorial candidate must raise $290,000; a State Senate candidate $17,300; and a State House candidate $5,800 from these small-dollar donors.', 'https://seec.ct.gov/Portal/data/CEP/news/2026CEPOverview.pdf', 'Connecticut SEEC - 2026 CEP Guide', '2026-05-17', 'per_cycle', 'official_source_direct', 'State candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('e32430da7615b6fb', 'CT', '["state"]', 'finance_ethics', 'What grant amounts do candidates receive under Connecticut''s Citizens'' Election Program (CEP)?', '["How much money do candidates get from public financing in CT?","CEP grant amounts Connecticut","Connecticut campaign spending limits CEP"]', 'Once qualified for the CEP, candidates receive a public grant and must abide by strict spending limits. For the 2026 general election, gubernatorial candidates receive approximately $7.7 million, State Senate candidates receive roughly $112,000, and State House candidates receive approximately $33,000.', 'https://seec.ct.gov/Portal/data/CEP/news/2026CEPOverview.pdf', 'Connecticut SEEC - 2026 CEP Guide', '2026-05-17', 'per_cycle', 'official_source_direct', 'State candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('f551b7aa580f10bb', 'CT', '["federal","state"]', 'redistricting', 'Who draws Connecticut''s congressional and state legislative maps?', '["Does the CT legislature draw district maps?","Who has the authority to draw district lines in Connecticut?","Connecticut redistricting commission"]', 'In Connecticut, the state legislature does NOT draw district maps directly. Instead, redistricting is handled by a bipartisan, 9-member Reapportionment Commission. The commission consists of eight members appointed by legislative leaders (four Democrats, four Republicans), who then select a ninth member to serve as the tie-breaking chair.', 'https://ballotpedia.org/Redistricting_in_Connecticut', 'Ballotpedia - Redistricting in Connecticut', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('95f2b54a1846bed7', 'CT', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Connecticut?', '["Standards for drawing Connecticut district lines","Connecticut gerrymandering rules","Map requirements CT"]', 'Under the Connecticut Constitution, redistricting maps must comply with federal equal population standards, the Voting Rights Act, and ensure districts are contiguous. Furthermore, town boundaries must be preserved to the extent possible, meaning towns cannot be divided to form districts unless absolutely necessary for population equality.', 'https://ballotpedia.org/Redistricting_in_Connecticut', 'Connecticut Constitution', '2026-05-17', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('699b746c2865e7bd', 'CT', '["state"]', 'redistricting', 'Are the current Connecticut redistricting maps operative for the 2026 cycle?', '["Status of Connecticut legislative redistricting maps","Are there pending redistricting lawsuits in Connecticut?","Connecticut 2026 state legislative boundaries"]', 'Yes. The state legislative and congressional maps adopted by the Reapportionment Commission in early 2022 (following the 2020 census) remain fully operative for the 2026 election cycle without any overriding legal injunctions.', 'https://www.cga.ct.gov/red2021/', 'Connecticut General Assembly - Reapportionment', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('4a149648df11b738', 'CT', '["federal","state"]', 'ballot_access', 'What is the petition signature threshold for independent candidates in Connecticut?', '["Independent candidate ballot access Connecticut","Running without a party in CT 2026","How many signatures for independent US Senate CT"]', 'Independent (petitioning) candidates can qualify for the general election ballot by gathering signatures equal to 1% of all votes cast for the same office at the preceding election, or 7,500 signatures, whichever is less. The deadline to submit these petitions is typically early August.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State - Nominating Petitions', '2026-05-17', 'static', 'official_source_direct', 'Independent candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('9dfcc6954abfd16d', 'CT', '["state"]', 'recall_rules', 'Does Connecticut have a recall mechanism for state officials?', '["Can the Governor of Connecticut be recalled?","How to recall a state senator in CT","Statewide recall election rules Connecticut"]', 'No. The State of Connecticut does not have any legal or constitutional mechanism for the recall of state-level elected officials, including the Governor, statewide executives, or members of the General Assembly.', 'https://ballotpedia.org/Laws_governing_recall_in_Connecticut', 'Laws governing recall in Connecticut', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('3edc5c7f0c6bb960', 'CT', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Connecticut?', '["Connecticut town council recall rules","Signature requirement local recall Connecticut","Recalling a mayor in CT"]', 'There is no statewide statutory right to local recall in Connecticut. Recall is only permitted in a few specific municipalities if their local town or city charter explicitly authorizes it (e.g., Stratford or Westport), meaning most local officials cannot be recalled.', 'https://ballotpedia.org/Laws_governing_recall_in_Connecticut', 'Laws governing recall in Connecticut', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('586a9c0b64428a61', 'CT', '["state"]', 'ballot_access', 'Does Connecticut have a citizen initiative process?', '["How to get an initiative on the CT ballot","Connecticut citizen initiative signature requirements","Can citizens propose laws in Connecticut?"]', 'No. Connecticut is one of the states that does NOT have a statewide citizen initiative process. Citizens cannot draft statutes or constitutional amendments and gather signatures to place them on the ballot. All statewide ballot measures must be referred by the legislature.', 'https://ballotpedia.org/Initiative_and_referendum_in_Connecticut', 'Ballotpedia - Initiative and Referendum in Connecticut', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('90bf04bec8067db2', 'CT', '["state"]', 'ballot_access', 'How does the Connecticut legislature refer a constitutional amendment to the voters?', '["Legislative referral process Connecticut","Referendum by legislature CT","Can the CT legislature put a constitutional amendment on the ballot?"]', 'The Connecticut General Assembly can refer a constitutional amendment to the ballot in two ways: by passing it with a 75% (3/4) supermajority in one legislative session, OR by passing it with a simple majority (over 50%) in two consecutive legislative sessions. After either path, it goes to the voters for ratification.', 'https://ballotpedia.org/Amending_the_Connecticut_Constitution', 'Connecticut Constitution Article XII', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('d90e18072099dcad', 'CT', '["state"]', 'ballot_access', 'Does Connecticut have a veto referendum process?', '["How to refer a CT bill to the ballot","Connecticut citizen referendum rules","Veto referendum signature threshold Connecticut state"]', 'No. Connecticut does not have a statewide veto referendum process. Citizens cannot gather signatures to suspend and refer legislative acts to the ballot for a popular vote of approval or rejection.', 'https://ballotpedia.org/Initiative_and_referendum_in_Connecticut', 'Ballotpedia - Initiative and Referendum in Connecticut', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('64933b69baba81fc', 'CT', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Connecticut?', '["Connecticut ballot measure pass threshold","Does a measure need a supermajority in CT?","Majority vote requirements Connecticut ballot measures"]', 'In Connecticut, a legislatively referred constitutional amendment requires only a simple majority (over 50%) of the total votes cast on that specific measure by the voters during a general election to pass.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T19-58-55_connecticut_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('2bf8c320ea9f4339', 'CT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Attorney General in Connecticut?', '["Qualifications to run for Attorney General in CT","Do I need to be a member of the bar to be CT AG?","Legal requirements for Connecticut Attorney General"]', 'The Connecticut Attorney General must be a qualified elector and an attorney at law who has maintained an active practice at the bar of the State of Connecticut for at least 10 years immediately preceding the election.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('c97d5c6dff17e0cd', 'CT', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of the State in Connecticut?', '["Requirements to run for CT Secretary of State","Who can run for Secretary of State in CT?","Residency rules for Connecticut SOS"]', 'To run for Secretary of the State in Connecticut, a candidate must be at least 18 years old and a registered voter (elector) in the state. There are no specialized professional qualifications required.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('fa2249a5eb316ce0', 'CT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Comptroller in Connecticut?', '["Eligibility for Connecticut State Comptroller","Who can run for Comptroller in CT?","Connecticut Comptroller residency requirements"]', 'To run for State Comptroller in Connecticut, a candidate must be at least 18 years old and a registered voter (elector) in the state. No specific financial or accounting licensure (such as a CPA) is constitutionally required.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('ca62838f4b353164', 'CT', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Connecticut?', '["Run for school board Connecticut requirements","Who can be a school board member in CT?","School board residency rules Connecticut"]', 'To run for a local Board of Education in Connecticut, candidates must be at least 18 years old, a registered voter, and a resident of the town or regional school district they seek to represent. Employees of a school board may not serve as board members for the district where they are employed.', 'https://portal.ct.gov/SOTS/Election-Services/Candidate-Information/Candidate-Information', 'Connecticut Secretary of the State - Local Offices', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('9ae38df3f1469498', 'CT', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for Connecticut Supreme Court justices?', '["Connecticut Supreme Court Justice eligibility","Years of practice required for CT Supreme Court","Are Connecticut judges elected or appointed?"]', 'To be appointed to the Connecticut Supreme Court, an individual must be a licensed attorney. They are nominated by the Governor from a list of candidates approved by the Judicial Selection Commission and must be confirmed by the General Assembly. They must retire at age 70.', 'https://www.jud.ct.gov/', 'State of Connecticut Judicial Branch', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('61806f0434cc6425', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee mail-in ballots in Connecticut?', '["How to fix a rejected signature in CT","Connecticut ballot cure process deadline","Missing signature on CT mail ballot"]', 'Yes. Following legislation passed in 2023, Connecticut instituted a signature cure process. If a town clerk determines an absentee ballot has a missing signature or missing inner envelope, they must notify the voter within 48 hours. The voter then has until Election Day to cure the defect to have the ballot counted.', 'https://cga.ct.gov/2023/ACT/PA/PDF/2023PA-00205-R00HB-06826-PA.PDF', 'Connecticut General Assembly (PA 23-205)', '2026-05-17', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('f0f7c716d49ef322', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Connecticut?', '["When are military ballots due in Connecticut?","UOCAVA return deadline CT","Overseas voting rules Connecticut state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. Voted ballots must be received by the local town clerk by the close of polls (8:00 p.m.) on Election Day to be counted. Connecticut does not accept postmarks for late-arriving ballots.', 'https://portal.ct.gov/SOTS/Election-Services/Voter-Information/Military-and-Overseas-Voters', 'Connecticut Secretary of the State - UOCAVA', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('b21cd8bdfae48d1f', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Connecticut?', '["What is a provisional ballot in CT?","Voting without ID Connecticut","When do election workers issue provisional ballots?"]', 'Provisional ballots are used in Connecticut but typically only for federal elections if a voter''s name does not appear on the official registry list. The voter must sign a sworn affidavit. For state and local races, voters generally must resolve their registration status at a Same-Day Registration (SDR) location rather than casting a provisional ballot.', 'https://portal.ct.gov/SOTS/Election-Services/FAQ/FAQ---Voter-Rights', 'Connecticut Secretary of the State - Voter Rights', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('954afe22815ae8d7', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Connecticut have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Connecticut DMV?","CT motor voter automatic registration","Do I have to register to vote if I get a CT driver''s license?"]', 'Yes. Connecticut operates an Automatic Voter Registration (AVR) system. Eligible citizens interacting with the DMV or other designated state agencies (like the Department of Social Services) are automatically registered to vote or have their records updated, unless they actively decline (opt out).', 'https://portal.ct.gov/SOTS/Election-Services/Voter-Information/Voter-Registration-Information', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('838b4cf61dbd453f', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Connecticut offer Online Voter Registration?', '["Can I register to vote online in CT?","Connecticut electronic voter registration","CT online registration portal"]', 'Yes. Eligible Connecticut residents with a valid state driver''s license or DMV-issued ID card can register to vote or update their registration using the state''s online portal up to 7 days before an election.', 'https://voterregistration.ct.gov/OLVR', 'Connecticut Secretary of the State - Online Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('a3cade5c52f0c4cb', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Connecticut maintain its voter registration lists?', '["CT voter list maintenance rules","How are inactive voters handled in Connecticut?","Connecticut voter roll cleaning process"]', 'Connecticut maintains its voter rolls using the Electronic Registration Information Center (ERIC) and National Change of Address (NCOA) data. Town registrars conduct annual canvasses. Voters who do not respond to confirmation notices and fail to vote in two consecutive federal general elections are moved to inactive status and eventually purged.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('92e332967cf49f76', 'CT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee ballot in Connecticut?', '["When is the last day to mail my ballot in CT?","Connecticut mail ballot postmark deadline","What time are ballots due in Connecticut?"]', 'Voted absentee ballots must be physically received by the municipal town clerk by the close of polls (8:00 p.m.) on Election Day. They can be mailed, deposited in a secure local drop box, or hand-delivered to the clerk''s office. Connecticut does NOT accept late-arriving ballots based on postmark dates.', 'https://portal.ct.gov/SOTS/Election-Services/Voter-Information/Absentee-Voting', 'Connecticut Secretary of the State - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('f2e6792e969bfa7c', 'CT', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Connecticut?', '["Does Connecticut use ranked choice voting?","RCV status in Connecticut 2026","Instant runoff voting CT"]', 'No. Ranked Choice Voting (RCV) is not used for any state, federal, or municipal elections in Connecticut. Elections are decided strictly by a traditional plurality voting system.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('9384d52d247af91f', 'CT', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in Connecticut elections?', '["How are tied elections decided in Connecticut?","Tie-breaker rules Connecticut elections","What happens if a race is tied in CT?"]', 'In the event of an exact tie for a state or federal office in Connecticut, state law requires a special election to be held to determine the winner, rather than breaking the tie by casting lots (drawing straws) as is common in many other states.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('9d5a1f5909b2020f', 'CT', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Connecticut campaign materials?', '["Connecticut ''Paid for by'' rules","Campaign ad disclaimer requirements CT","Political taglines Connecticut SEEC"]', 'Connecticut campaign finance law requires political advertisements to include ''Paid for by'' disclaimers identifying the entity funding the communication. For candidate-sponsored ads, it must also include a clear ''Approved by [Candidate Name]'' statement. Participants in the Citizens'' Election Program (CEP) must explicitly note their participation in the program.', 'https://seec.ct.gov/', 'Connecticut SEEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('521b26bf5b259b70', 'CT', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Connecticut?', '["CT campaign coordination rules","When is a PAC expenditure not independent in Connecticut?","Prohibition on candidate-PAC coordination CT"]', 'An independent expenditure becomes ''coordinated'' if made with the consent, coordination, or consultation of a candidate. Coordinated expenditures are treated as in-kind contributions, subject to strict limits, and accepting them can critically disqualify a candidate from participating in the Citizens'' Election Program (CEP).', 'https://seec.ct.gov/Portal/data/CEP/news/2026CEPOverview.pdf', 'Connecticut SEEC - CEP Guidelines', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('7c5841024c0831de', 'CT', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Connecticut?', '["CT SEEC late fee","Penalty for missing a Connecticut campaign finance deadline","Elections Enforcement Commission fine for late filing CT"]', 'The SEEC imposes a mandatory $100 late fee for failing to file a campaign finance report on time. Further failure can trigger significantly higher civil penalties. Additionally, candidates seeking public funds via the CEP can forfeit their eligibility if their qualifying reports are chronically late or flawed.', 'https://seec.ct.gov/Portal/eCRIS/eCRISHome', 'Connecticut SEEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('60e8e2c81b011e12', 'CT', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Connecticut campaign committee terminate?', '["Closing a Connecticut campaign committee","SEEC committee termination requirements","Final campaign finance report Connecticut"]', 'A candidate committee may formally terminate when it achieves a zero cash balance, legally disposes of all unexpended funds, and resolves all outstanding debts. A formal Termination Report must be filed with the SEEC through the eCRIS portal.', 'https://seec.ct.gov/', 'Connecticut SEEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('93b088e2eca7250c', 'CT', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Connecticut?', '["CT independent expenditure reporting SEEC","Disclosure for CT independent expenditure groups","Reporting thresholds for outside spending Connecticut"]', 'Entities making independent expenditures of more than $1,000 must file long-form disclosure reports with the SEEC. In the 90 days before a primary or general election, they trigger a 24-hour rapid disclosure requirement for expenditures exceeding the $1,000 threshold.', 'https://seec.ct.gov/', 'Connecticut SEEC', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('d0cc7329f605d63a', 'CT', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Connecticut?', '["Connecticut in-kind contribution valuation rules","Reporting non-monetary donations Connecticut campaign","Fair market value for in-kind gifts CT"]', 'In-kind contributions must be reported to the SEEC at their fair market value. They count directly against the donor''s per-election monetary contribution limit. For CEP candidates, receiving in-kind contributions beyond strict limits can jeopardize their public financing grant.', 'https://seec.ct.gov/', 'Connecticut SEEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('093927a48359ab70', 'CT', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Connecticut?', '["Connecticut candidate personal loan limits","Can I pay myself back for a campaign loan in CT?","Reporting candidate loans in SEEC"]', 'For traditionally funded candidates, personal loans are unlimited. However, for candidates participating in the Citizens'' Election Program (CEP), strict limits apply (e.g., gubernatorial candidates can only self-fund up to $20,000) because they must rely on small-dollar donors and public grants.', 'https://seec.ct.gov/Portal/data/CEP/news/2026CEPOverview.pdf', 'Connecticut SEEC - 2026 CEP Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('c77e0dac694224fe', 'CT', '["state","county","municipal"]', 'finance_ethics', 'What can Connecticut candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in CT?","CT surplus campaign funds rules","Donating remaining campaign funds Connecticut"]', 'Candidates participating in the CEP MUST return all unexpended surplus grant funds directly to the Citizens'' Election Fund. Non-CEP candidates can donate surplus funds to an IRS-recognized tax-exempt charitable organization or specific political town committees, but they cannot convert the funds to personal use.', 'https://seec.ct.gov/', 'Connecticut SEEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('359449874ada2e5b', 'CT', '["municipal"]', 'election_dates', 'When are municipal elections held in Connecticut?', '["Connecticut local election dates","When are mayors elected in CT?","Town council election cycle Connecticut"]', 'Municipal elections in Connecticut are completely disjointed from federal elections. The vast majority of the 169 towns hold their local elections in November of odd-numbered years, though a small number hold them in May of odd-numbered years.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Local candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('0697e36c1cf0036d', 'CT', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Connecticut elections?', '["When are Connecticut election results official?","CT certification deadline","State Board of Canvassers meeting Connecticut"]', 'Local Head Moderators compile and certify results on election night. Town clerks submit official returns within 48 hours. The State Board of Canvassers officially declares the state/federal results by the last day of November.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('3bcb029501fbfd2c', 'CT', '["federal","state"]', 'election_dates', 'When and how are special elections called in Connecticut?', '["Connecticut special election timeline","Who calls a special election to fill a US House vacancy in CT?","Filling a midterm vacancy Connecticut"]', 'Special elections for legislative vacancies are called by a Writ of Election issued by the Governor. The election is generally held exactly 46 days after the writ is issued.', 'https://portal.ct.gov/SOTS', 'Connecticut Secretary of the State', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1'),
  ('01cf3fe5fe6b343c', 'CT', '["state"]', 'election_dates', 'Who sits on the Connecticut State Elections Enforcement Commission (SEEC)?', '["Who oversees campaign finance in CT?","Connecticut SEEC composition","Who appoints the State Elections Enforcement Commission?"]', 'The State Elections Enforcement Commission (SEEC) is an independent, bipartisan body consisting of five members. They are appointed by the Governor and the four highest-ranking leaders of the General Assembly.', 'https://seec.ct.gov/Portal/AboutUs', 'Connecticut SEEC', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-58-55_connecticut_full_v1')
